spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var stage = 1;
    if (progress >= 0.25 && progress < 0.54) stage = 2;
    else if (progress >= 0.54 && progress < 0.79) stage = 3;
    else if (progress >= 0.79) stage = 4;

    var midY = H / 2 - 35;

    // Helper to draw a coin bag
    function drawBag(bx, by, drawCoins, coinCount) {
      // Bag shape (draw a simple draw-string bag style)
      ctx.fillStyle = '#10B981'; // Green bag
      ctx.beginPath();
      ctx.arc(bx, by + 4, 12, 0.15 * Math.PI, 0.85 * Math.PI, true);
      ctx.lineTo(bx - 4, by - 12);
      ctx.lineTo(bx + 4, by - 12);
      ctx.closePath();
      ctx.fill();

      // Draw tie ribbon
      ctx.fillStyle = '#F59E0B';
      ctx.fillRect(bx - 6, by - 7, 12, 2);

      // Bag label '1'
      ctx.fillStyle = '#FFFFFF';
      ctx.font = 'bold 9px monospace';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText('1', bx, by + 3);

      if (drawCoins) {
        // Spill coins underneath
        ctx.fillStyle = '#F59E0B';
        for (var i = 0; i < coinCount; i++) {
          var cx = bx - 14 + (i * 7);
          var cy = by + 22;
          ctx.beginPath();
          ctx.arc(cx, cy, 2.5, 0, Math.PI * 2);
          ctx.fill();
        }
      }
    }

    // Stage drawing
    if (stage === 1) {
      // Draw 4 bags
      var startX = W / 2 - 45;
      for (var i = 0; i < 4; i++) {
        drawBag(startX + i * 30, midY, false);
      }
    } else if (stage === 2) {
      // Draw 1 bag with 5 spilled coins
      drawBag(W / 2, midY, true, 5);
    } else if (stage >= 3) {
      // Draw 7 bags
      var startX = W / 2 - 90;
      for (var i = 0; i < 7; i++) {
        drawBag(startX + i * 30, midY, false);
      }
    }

    // Details text on canvas
    ctx.font = 'bold 15px -apple-system, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillStyle = '#F3F4F6';

    if (stage === 1) {
      ctx.fillText('Given: 4 Bags = 20 Coins', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('We want to find how many coins are in 7 bags.', W / 2, H - 22);
    } else if (stage === 2) {
      ctx.fillStyle = '#60A5FA';
      ctx.fillText('Step 1: Find Coins in 1 Bag', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Divide total coins by bags: 20 ÷ 4 = 5 coins per bag.', W / 2, H - 22);
    } else if (stage === 3) {
      ctx.fillStyle = '#F59E0B';
      ctx.fillText('Step 2: Scale up to 7 Bags', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Multiply unit value by 7 bags: 5 coins × 7 = 35 coins.', W / 2, H - 22);
    } else {
      ctx.fillStyle = '#10B981';
      ctx.fillText('Result = 35 Coins', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('The unitary method successfully scaled the coins: 7 bags = 35.', W / 2, H - 22);
    }
  }
};
